1	// k-NN sizing engine — OWNED by Dev B
2	// In-memory over the Reonic dataset (1620 status_quo rows × ~20 BOM line items each).
3	// Primary source of truth for kWp / kWh / heatpump / similar-projects in /api/design.
4	//
5	// Data convention (Reonic CSVs):
6	// - All energy columns are stored in Wh (e.g. energy_demand_wh = 4_500_000 → 4500 kWh)
7	// - All "_kwh" / "_kw" columns are ALSO stored in Wh / W (e.g. battery_capacity_kwh = 12_000 → 12 kWh)
8	// - module_watt_peak is in W per panel (e.g. 475 → 475 Wp)
9	// We normalize everything to kWh / kW internally.
10	
11	import fs from 'node:fs';
12	import path from 'node:path';
13	import type { CustomerProfile, DesignResult, SimilarProject } from './types';
14	
15	export interface ProjectRow {
16	  projectId: string;
17	  // Inputs (from status_quo)
18	  energyDemandKwh: number;
19	  hasEv: number;          // 0/1
20	  evKm: number;
21	  heatingType: number;    // 0=oil, 1=gas, 2=heatpump, 3=other
22	  houseSizeSqm: number;
23	  inhabitants: number;
24	  // Outputs (aggregated from options_parts, option_number=1)
25	  totalKwp: number;
26	  batteryKwh: number;
27	  hasHeatPump: number;
28	  heatPumpKw: number;
29	  hasWallbox: number;
30	}
31	
32	const HEATING_MAP: Record<string, number> = {
33	  Oil: 0,
34	  oil: 0,
35	  Gas: 1,
36	  gas: 1,
37	  Heatpump: 2,
38	  heatpump: 2,
39	  OtherNonRenewable: 3,
40	  other: 3,
41	};
42	
43	let PROJECTS: ProjectRow[] | null = null;
44	let MEAN: number[] = [];
45	let STD: number[] = [];
46	
47	// --- CSV parser (tolerant, no quoted commas in this dataset) ---
48	function parseCsv(content: string): Record<string, string>[] {
49	  const lines = content.replace(/\r/g, '').trim().split('\n');
50	  if (lines.length === 0) return [];
51	  const headers = lines[0].split(',');
52	  return lines.slice(1).map((line) => {
53	    const fields = line.split(',');
54	    const row: Record<string, string> = {};
55	    for (let i = 0; i < headers.length; i++) row[headers[i]] = fields[i] ?? '';
56	    return row;
57	  });
58	}
59	
60	function num(s: string | undefined): number {
61	  if (!s) return 0;
62	  const v = parseFloat(s);
63	  return Number.isFinite(v) ? v : 0;
64	}
65	
66	function loadProjects(): ProjectRow[] {
67	  if (PROJECTS) return PROJECTS;
68	
69	  const dataDir = path.join(process.cwd(), 'data');
70	  const statusQuo = [
71	    parseCsv(fs.readFileSync(path.join(dataDir, 'projects_status_quo_1.csv'), 'utf-8')),
72	    parseCsv(fs.readFileSync(path.join(dataDir, 'projects_status_quo_2.csv'), 'utf-8')),
73	  ].flat();
74	
75	  const options = [
76	    parseCsv(fs.readFileSync(path.join(dataDir, 'project_options_parts_1.csv'), 'utf-8')),
77	    parseCsv(fs.readFileSync(path.join(dataDir, 'project_options_parts_2.csv'), 'utf-8')),
78	  ].flat();
79	
80	  // The Reonic dataset stores BOM info in messy ways across multiple line items.
81	  // Strategy: for each (project, option_number=1), aggregate signals from many sources.
82	  //
83	  // - kWp: max(qty) of ModuleFrameConstruction rows × 475W default panel (covers 721 projects)
84	  //        OR from "Hybrid Inverter XkW" / "PV Complete Package XkW" / "X.XkWp + YkWh" patterns
85	  // - Battery kWh: parse component_name regex on BatteryStorage rows
86	  // - Wallbox: any Wallbox component_type row OR wb_charging_speed_kw populated
87	  // - HeatPump: any Heatpump component_type row OR heatpump_nominal_power_kw populated
88	
89	  const KWP_FROM_NAME = /(\d+(?:\.\d+)?)\s*kWp/i;
90	  const KW_FROM_NAME = /(\d+(?:\.\d+)?)\s*kW(?![hp])/i; // kW but not kWh / kWp
91	  const KWH_FROM_NAME = /(\d+(?:\.\d+)?)\s*kWh/i;
92	  const DEFAULT_PANEL_W = 475;
93	
94	  const bomByProject = new Map<string, {
95	    panelCount: number;        // max qty across ModuleFrameConstruction rows
96	    explicitKwp: number;       // from package / inverter strings
97	    batteryKwh: number;
98	    hasHeatPump: number;
99	    heatPumpKw: number;
100	    hasWallbox: number;
101	  }>();
102	
103	  for (const row of options) {
104	    if (parseInt(row.option_number || '1', 10) !== 1) continue;
105	    const pid = row.project_id;
106	    const cur = bomByProject.get(pid) ?? {
107	      panelCount: 0, explicitKwp: 0, batteryKwh: 0,
108	      hasHeatPump: 0, heatPumpKw: 0, hasWallbox: 0,
109	    };
110	
111	    const ctype = row.component_type;
112	    const cname = row.component_name || '';
113	
114	    // --- kWp signals ---
115	    if (ctype === 'ModuleFrameConstruction') {
116	      const qty = num(row.quantity);
117	      if (qty > 0) cur.panelCount = Math.max(cur.panelCount, qty);
118	      // Also try "Substructure 8.8-15kWp" → take upper bound midpoint
119	      const m = cname.match(/(\d+(?:\.\d+)?)\s*-\s*(\d+(?:\.\d+)?)\s*kWp/i);
120	      if (m) cur.explicitKwp = Math.max(cur.explicitKwp, (parseFloat(m[1]) + parseFloat(m[2])) / 2);
121	    }
122	    if (ctype === 'Inverter') {
123	      const m = cname.match(KW_FROM_NAME);
124	      if (m) cur.explicitKwp = Math.max(cur.explicitKwp, parseFloat(m[1]));
125	    }
126	    if (ctype === 'ServiceFee' && /PV Complete Package/i.test(cname)) {
127	      const m = cname.match(KW_FROM_NAME);
128	      if (m) cur.explicitKwp = Math.max(cur.explicitKwp, parseFloat(m[1]));
129	    }
130	    if (ctype === 'Other' && /Complete Package/i.test(cname)) {
131	      // e.g. "Complete Package 2 Sigenergy 10.8kWp + 9kWh"
132	      const k = cname.match(KWP_FROM_NAME);
133	      if (k) cur.explicitKwp = Math.max(cur.explicitKwp, parseFloat(k[1]));
134	      const b = cname.match(KWH_FROM_NAME);
135	      if (b) cur.batteryKwh = Math.max(cur.batteryKwh, parseFloat(b[1]));
136	    }
137	    // Module-typed rows have module_watt_peak set (rare, ~71 rows)
138	    const moduleWatt = num(row.module_watt_peak);
139	    const qty = num(row.quantity);
140	    if (moduleWatt > 0 && qty > 0) {
141	      cur.explicitKwp = Math.max(cur.explicitKwp, (moduleWatt * qty) / 1000);
142	    }
143	
144	    // --- Battery ---
145	    if (ctype === 'BatteryStorage') {
146	      const m = cname.match(KWH_FROM_NAME);
147	      if (m) cur.batteryKwh = Math.max(cur.batteryKwh, parseFloat(m[1]));
148	      const colKwh = num(row.battery_capacity_kwh);
149	      if (colKwh > 0) cur.batteryKwh = Math.max(cur.batteryKwh, colKwh / 1000);
150	    }
151	
152	    // --- Wallbox ---
153	    if (ctype === 'Wallbox') cur.hasWallbox = 1;
154	    if (num(row.wb_charging_speed_kw) > 0) cur.hasWallbox = 1;
155	
156	    // --- Heat pump ---
157	    if (ctype === 'Heatpump') {
158	      cur.hasHeatPump = 1;
159	      const m = cname.match(KW_FROM_NAME);
160	      if (m) cur.heatPumpKw = Math.max(cur.heatPumpKw, parseFloat(m[1]));
161	    }
162	    const hpCol = num(row.heatpump_nominal_power_kw);
163	    if (hpCol > 0) {
164	      cur.hasHeatPump = 1;
165	      cur.heatPumpKw = Math.max(cur.heatPumpKw, hpCol / 1000);
166	    }
167	
168	    bomByProject.set(pid, cur);
169	  }
170	
171	  // Join with status_quo.
172	  //
173	  // The Reonic dataset is sparse on GDPR-sensitive fields: only 200/1620 rows have
174	  // heating_existing_type populated, only 8/1620 have house_size_sqm. When missing,
175	  // we synthesize plausible values from energy consumption and the BOM signals:
176	  // - house_size_sqm ≈ energyKwh / 35 (typical German residential 30-40 kWh/m²/yr),
177	  //   clamped to 60-300 m²
178	  // - heating_type: priority (a) if BOM offered HP → 'heatpump' (Reonic upsells HP);
179	  //   (b) if real value present, use it; (c) else market-weighted random
180	  //   (gas 55%, oil 25%, other 15%, heatpump 5%)
181	  // This is disclosed in the pitch: "synthesized when the dataset stripped the field for GDPR".
182	
